// Auto-migrated from the original static guide HTML. Structural markup
// and code samples are preserved; inline styles, scripts, and the guide's
// own bespoke syntax-highlight token classes were stripped so every guide
// renders through the one shared GuideReader stylesheet.
export const html: string = "<section class=\"step\" id=\"s1\">\n<div class=\"step-header\">\n<div class=\"step-badge\">01</div>\n<h2>Prerequisites</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A SaaS app touches more moving parts than a simple site -- a database server, a payment provider, and (eventually) a task queue. Confirming the toolchain now avoids debugging three problems at once later.</div>\n<div class=\"step-body\">\n<p>You need Python 3.10+, pip, and a PostgreSQL client. SQLite is fine for local dev but you'll move to Postgres before deploying, so it's worth having it installed from day one.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>python3 --version <span># 3.10 or newer</span>\npip3 --version\npsql --version <span># PostgreSQL client, optional for now</span>\nnode --version <span># only if you plan to add a build step for JS/CSS</span></pre>\n</div>\n<div>You do not need Node.js for this guide -- all CSS and JS below is hand-written, dependency-free, and served directly by Django's static files system. Add a build step later only if your team wants Tailwind or a bundler.</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Create a free <a href=\"https://dashboard.stripe.com/register\">Stripe</a> account now -- Step 18 uses your test API keys, and account verification can take a few minutes.</div>\n</section>\n<section class=\"step\" id=\"s2\">\n<div class=\"step-header\">\n<div class=\"step-badge\">02</div>\n<h2>Create a virtual environment</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Isolating dependencies per project means upgrading Django for one client app never breaks another. It also makes <code>requirements.txt</code> a trustworthy, reproducible list.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">your project root</span>\n</div>\n<pre>mkdir saasdash &amp;&amp; cd saasdash\npython3 -m venv venv\nsource venv/bin/activate <span># macOS / Linux</span>\n# venv\\Scripts\\activate <span># Windows PowerShell</span></pre>\n</div>\n<div>Your prompt will show <code>(venv)</code> once active. Run <code>deactivate</code> to leave it. Never commit the <code>venv/</code> folder -- add it to <code>.gitignore</code> in Step 5.</div>\n</section>\n<section class=\"step\" id=\"s3\">\n<div class=\"step-header\">\n<div class=\"step-badge\">03</div>\n<h2>Install dependencies</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Installing the full stack up front -- Django, Postgres driver, environment config, and Stripe -- means you won't hit a missing-package error mid-way through building a feature.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install django psycopg2-binary python-decouple stripe gunicorn whitenoise\npip freeze &gt; requirements.txt\npython -m django --version <span># should print 5.x</span></pre>\n</div>\n<div class=\"table-wrap\">\n<table>\n<tr><th>Package</th><th>Purpose</th></tr>\n<tr><td><code>django</code></td><td>The web framework itself</td></tr>\n<tr><td><code>psycopg2-binary</code></td><td>PostgreSQL database driver</td></tr>\n<tr><td><code>python-decouple</code></td><td>Reads settings from environment variables / <code>.env</code></td></tr>\n<tr><td><code>stripe</code></td><td>Official SDK for billing and subscriptions</td></tr>\n<tr><td><code>gunicorn</code></td><td>Production WSGI server (Step 24)</td></tr>\n<tr><td><code>whitenoise</code></td><td>Serves static files directly in production, no Nginx config needed</td></tr>\n</table>\n</div>\n</section>\n<section class=\"step\" id=\"s4\">\n<div class=\"step-header\">\n<div class=\"step-badge\">04</div>\n<h2>Create the project and apps</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A SaaS dashboard naturally splits into two concerns: <strong>accounts</strong> (who is logged in, which company they belong to, billing) and <strong>dashboard</strong> (the product itself). Separating them now keeps billing logic out of your product views.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">inside saasdash/</span>\n</div>\n<pre>django-admin startproject core . <span># the dot avoids a redundant outer folder</span>\npython manage.py startapp accounts\npython manage.py startapp dashboard</pre>\n</div>\n<div><strong>accounts</strong> owns the custom User model, signup/login, organizations (tenants), and Stripe subscriptions. <strong>dashboard</strong> owns the actual product screens -- stats, tables, settings -- that a logged-in user sees.</div>\n</section>\n<section class=\"step\" id=\"s5\">\n<div class=\"step-header\">\n<div class=\"step-badge\">05</div>\n<h2>Project structure</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Knowing exactly where templates, static files, and settings live prevents the most common beginner mistake: editing a file Django isn't actually loading.</div>\n<div>\n\n<div class=\"tree\" id=\"tree-s5\">\n<span>saasdash/</span>\n \u251c\u2500\u2500 <span>core/</span> <span># project package</span>\n \u2502 \u251c\u2500\u2500 <span>settings/</span> <span># split settings (Step 6)</span>\n \u2502 \u2502 \u251c\u2500\u2500 <span>__init__.py</span>\n \u2502 \u2502 \u251c\u2500\u2500 <span>base.py</span>\n \u2502 \u2502 \u251c\u2500\u2500 <span>dev.py</span>\n \u2502 \u2502 \u2514\u2500\u2500 <span>prod.py</span>\n \u2502 \u251c\u2500\u2500 <span>urls.py</span>\n \u2502 \u251c\u2500\u2500 <span>asgi.py</span>\n \u2502 \u2514\u2500\u2500 <span>wsgi.py</span>\n \u251c\u2500\u2500 <span>accounts/</span> <span># auth, tenants, billing</span>\n \u2502 \u251c\u2500\u2500 <span>models.py</span>\n \u2502 \u251c\u2500\u2500 <span>views.py</span>\n \u2502 \u251c\u2500\u2500 <span>forms.py</span>\n \u2502 \u251c\u2500\u2500 <span>urls.py</span>\n \u2502 \u2514\u2500\u2500 <span>admin.py</span>\n \u251c\u2500\u2500 <span>dashboard/</span> <span># product screens</span>\n \u2502 \u251c\u2500\u2500 <span>models.py</span>\n \u2502 \u251c\u2500\u2500 <span>views.py</span>\n \u2502 \u2514\u2500\u2500 <span>urls.py</span>\n \u251c\u2500\u2500 <span>templates/</span> <span># project-level templates (create this)</span>\n \u2502 \u251c\u2500\u2500 <span>base.html</span>\n \u2502 \u251c\u2500\u2500 <span>accounts/</span>\n \u2502 \u2514\u2500\u2500 <span>dashboard/</span>\n \u251c\u2500\u2500 <span>static/</span> <span># project-level static source (create this)</span>\n \u2502 \u251c\u2500\u2500 <span>css/</span>\n \u2502 \u2514\u2500\u2500 <span>js/</span>\n \u251c\u2500\u2500 <span>venv/</span> <span># never commit</span>\n \u251c\u2500\u2500 <span>.env</span> <span># never commit</span>\n \u251c\u2500\u2500 <span>.gitignore</span>\n \u251c\u2500\u2500 <span>manage.py</span>\n \u2514\u2500\u2500 <span>requirements.txt</span>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">.gitignore</span>\n</div>\n<pre>venv/\n.env\n__pycache__/\n*.pyc\ndb.sqlite3\nstaticfiles/\nmedia/\n.DS_Store</pre>\n</div>\n<div class=\"tone-danger\"><strong>Watch out:</strong> <code>.env</code> holds your secret key, database credentials, and Stripe keys. If it ever gets committed, rotate every key in it immediately -- don't just delete the commit.</div>\n</section>\n<section class=\"step\" id=\"s6\">\n<div class=\"step-header\">\n<div class=\"step-badge\">06</div>\n<h2>Split settings into base / dev / prod</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A single <code>settings.py</code> tempts you to hardcode <code>DEBUG = True</code> and ship it. Splitting settings by environment makes \"which config am I running\" an explicit choice, not an accident.</div>\n<div class=\"step-body\">\n<p>Delete the generated <code>core/settings.py</code> and replace it with a <code>core/settings/</code> package.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>rm core/settings.py\nmkdir core/settings\ntouch core/settings/__init__.py core/settings/base.py core/settings/dev.py core/settings/prod.py</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/base.py</span>\n</div>\n<pre><span>from</span> pathlib <span>import</span> Path\n<span>from</span> decouple <span>import</span> config\n\nBASE_DIR = Path(__file__).resolve().parent.parent.parent\n\nSECRET_KEY = config(<span>\"SECRET_KEY\"</span>)\nAUTH_USER_MODEL = <span>\"accounts.User\"</span>\n\nINSTALLED_APPS = [\n <span>\"django.contrib.admin\"</span>,\n <span>\"django.contrib.auth\"</span>,\n <span>\"django.contrib.contenttypes\"</span>,\n <span>\"django.contrib.sessions\"</span>,\n <span>\"django.contrib.messages\"</span>,\n <span>\"django.contrib.staticfiles\"</span>,\n <span>\"accounts\"</span>,\n <span>\"dashboard\"</span>,\n]\n\nMIDDLEWARE = [\n <span>\"django.middleware.security.SecurityMiddleware\"</span>,\n <span>\"whitenoise.middleware.WhiteNoiseMiddleware\"</span>,\n <span>\"django.contrib.sessions.middleware.SessionMiddleware\"</span>,\n <span>\"django.middleware.common.CommonMiddleware\"</span>,\n <span>\"django.middleware.csrf.CsrfViewMiddleware\"</span>,\n <span>\"django.contrib.auth.middleware.AuthenticationMiddleware\"</span>,\n <span>\"django.contrib.messages.middleware.MessageMiddleware\"</span>,\n <span>\"django.middleware.clickjacking.XFrameOptionsMiddleware\"</span>,\n <span>\"accounts.middleware.CurrentOrganizationMiddleware\"</span>, <span># Step 8</span>\n]\n\nROOT_URLCONF = <span>\"core.urls\"</span>\n\nTEMPLATES = [{\n <span>\"BACKEND\"</span>: <span>\"django.template.backends.django.DjangoTemplates\"</span>,\n <span>\"DIRS\"</span>: [BASE_DIR / <span>\"templates\"</span>],\n <span>\"APP_DIRS\"</span>: <span>True</span>,\n <span>\"OPTIONS\"</span>: {\n <span>\"context_processors\"</span>: [\n <span>\"django.template.context_processors.debug\"</span>,\n <span>\"django.template.context_processors.request\"</span>,\n <span>\"django.contrib.auth.context_processors.auth\"</span>,\n <span>\"django.contrib.messages.context_processors.messages\"</span>,\n <span>\"accounts.context_processors.current_organization\"</span>, <span># Step 8</span>\n ],\n },\n}]\n\nWSGI_APPLICATION = <span>\"core.wsgi.application\"</span>\n\nLANGUAGE_CODE = <span>\"en-us\"</span>\nTIME_ZONE = <span>\"UTC\"</span>\nUSE_I18N = <span>True</span>\nUSE_TZ = <span>True</span>\n\nSTATIC_URL = <span>\"static/\"</span>\nSTATICFILES_DIRS = [BASE_DIR / <span>\"static\"</span>]\nSTATIC_ROOT = BASE_DIR / <span>\"staticfiles\"</span>\nSTATICFILES_STORAGE = <span>\"whitenoise.storage.CompressedManifestStaticFilesStorage\"</span>\n\nMEDIA_URL = <span>\"media/\"</span>\nMEDIA_ROOT = BASE_DIR / <span>\"media\"</span>\n\nDEFAULT_AUTO_FIELD = <span>\"django.db.models.BigAutoField\"</span>\n\nLOGIN_URL = <span>\"accounts:login\"</span>\nLOGIN_REDIRECT_URL = <span>\"dashboard:home\"</span>\nLOGOUT_REDIRECT_URL = <span>\"accounts:login\"</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/dev.py</span>\n</div>\n<pre><span>from</span> .base <span>import</span> *\n\nDEBUG = <span>True</span>\nALLOWED_HOSTS = [<span>\"localhost\"</span>, <span>\"127.0.0.1\"</span>]\n\nDATABASES = {\n <span>\"default\"</span>: {\n <span>\"ENGINE\"</span>: <span>\"django.db.backends.sqlite3\"</span>,\n <span>\"NAME\"</span>: BASE_DIR / <span>\"db.sqlite3\"</span>,\n }\n}</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/prod.py</span>\n</div>\n<pre><span>from</span> .base <span>import</span> *\n<span>import</span> dj_database_url\n\nDEBUG = <span>False</span>\nALLOWED_HOSTS = config(<span>\"ALLOWED_HOSTS\"</span>, cast=<span>lambda</span> v: v.split(<span>\",\"</span>))\n\nDATABASES = {\n <span>\"default\"</span>: dj_database_url.config(\n default=config(<span>\"DATABASE_URL\"</span>)\n )\n}\n\nSECURE_SSL_REDIRECT = <span>True</span>\nSESSION_COOKIE_SECURE = <span>True</span>\nCSRF_COOKIE_SECURE = <span>True</span>\nSECURE_HSTS_SECONDS = <span>31536000</span>\nSECURE_HSTS_INCLUDE_SUBDOMAINS = <span>True</span>\nSECURE_CONTENT_TYPE_NOSNIFF = <span>True</span>\nX_FRAME_OPTIONS = <span>\"DENY\"</span></pre>\n</div>\n<div>Add <code>pip install dj-database-url</code> to parse <code>DATABASE_URL</code> connection strings (the format most hosts like Railway, Render, and Heroku give you). Run Django with <code>DJANGO_SETTINGS_MODULE=core.settings.dev</code> locally and <code>core.settings.prod</code> in production -- set this in <code>manage.py</code>, <code>wsgi.py</code>, or your host's environment variables.</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Generate a strong secret key with <code>python -c \"from django.core.management.utils import get_random_secret_key; print(get_random_secret_key())\"</code> and put it only in <code>.env</code>, never in code.</div>\n</section>\n<section class=\"step\" id=\"s7\">\n<div class=\"step-header\">\n<div class=\"step-badge\">07</div>\n<h2>Custom user model</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django strongly recommends starting every project with a custom user model, even if it looks identical to the default at first. Swapping it in later requires a risky database migration -- doing it now costs nothing.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/models.py</span>\n</div>\n<pre><span>from</span> django.contrib.auth.models <span>import</span> AbstractUser\n<span>from</span> django.db <span>import</span> models\n\n\n<span>class</span> <span>User</span>(AbstractUser):\n email = models.EmailField(unique=<span>True</span>)\n\n USERNAME_FIELD = <span>\"email\"</span>\n REQUIRED_FIELDS = [<span>\"username\"</span>]\n\n <span>def</span> <span>__str__</span>(self):\n <span>return</span> self.email</pre>\n</div>\n<div>Setting <code>USERNAME_FIELD = \"email\"</code> lets users log in with their email instead of a separate username. You still need <code>username</code> populated internally because <code>AbstractUser</code> requires it -- many teams auto-generate it from the email in a signal or form <code>save()</code>.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>python manage.py makemigrations accounts\npython manage.py migrate</pre>\n</div>\n<div class=\"tone-danger\"><strong>Watch out:</strong> <code>AUTH_USER_MODEL</code> must be set in settings <em>before</em> your first migration ever runs. If you already ran <code>migrate</code> with the default user model, you'll need to reset the database -- there's no clean in-place swap.</div>\n</section>\n<section class=\"step\" id=\"s8\">\n<div class=\"step-header\">\n<div class=\"step-badge\">08</div>\n<h2>Multi-tenancy: organizations</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Almost every real SaaS product is multi-tenant: a user belongs to a company/workspace, and every data row belongs to that workspace, not just to a user. Modeling this now means every later feature -- billing, permissions, dashboards -- filters by organization \"for free.\"</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/models.py (continued)</span>\n</div>\n<pre><span>import</span> uuid\n\n\n<span>class</span> <span>Organization</span>(models.Model):\n id = models.UUIDField(primary_key=<span>True</span>, default=uuid.uuid4, editable=<span>False</span>)\n name = models.CharField(max_length=<span>120</span>)\n slug = models.SlugField(unique=<span>True</span>)\n created_at = models.DateTimeField(auto_now_add=<span>True</span>)\n\n <span># filled in once Stripe is wired up in Step 18</span>\n stripe_customer_id = models.CharField(max_length=<span>120</span>, blank=<span>True</span>, default=<span>\"\"</span>)\n plan = models.CharField(\n max_length=<span>20</span>,\n choices=[(<span>\"free\"</span>, <span>\"Free\"</span>), (<span>\"pro\"</span>, <span>\"Pro\"</span>), (<span>\"team\"</span>, <span>\"Team\"</span>)],\n default=<span>\"free\"</span>,\n )\n\n <span>def</span> <span>__str__</span>(self):\n <span>return</span> self.name\n\n\n<span>class</span> <span>Membership</span>(models.Model):\n <span># the join table between users and organizations, with a role</span>\n ROLE_CHOICES = [(<span>\"owner\"</span>, <span>\"Owner\"</span>), (<span>\"admin\"</span>, <span>\"Admin\"</span>), (<span>\"member\"</span>, <span>\"Member\"</span>)]\n\n user = models.ForeignKey(<span>\"accounts.User\"</span>, on_delete=models.CASCADE, related_name=<span>\"memberships\"</span>)\n organization = models.ForeignKey(Organization, on_delete=models.CASCADE, related_name=<span>\"memberships\"</span>)\n role = models.CharField(max_length=<span>10</span>, choices=ROLE_CHOICES, default=<span>\"member\"</span>)\n created_at = models.DateTimeField(auto_now_add=<span>True</span>)\n\n <span>class</span> <span>Meta</span>:\n unique_together = [<span>\"user\"</span>, <span>\"organization\"</span>]\n\n <span>def</span> <span>__str__</span>(self):\n <span>return</span> <span>f</span><span>\"{self.user} @ {self.organization} ({self.role})\"</span></pre>\n</div>\n<div class=\"step-body\">\n<p>A user can belong to more than one organization (think: a freelancer working with several clients). The <strong>currently active</strong> organization is tracked in the session. A middleware resolves it on every request so views never have to think about it:</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/middleware.py</span>\n</div>\n<pre><span>from</span> .models <span>import</span> Organization\n\n\n<span>class</span> <span>CurrentOrganizationMiddleware</span>:\n <span>def</span> <span>__init__</span>(self, get_response):\n self.get_response = get_response\n\n <span>def</span> <span>__call__</span>(self, request):\n request.organization = <span>None</span>\n <span>if</span> request.user.is_authenticated:\n org_id = request.session.get(<span>\"active_org_id\"</span>)\n membership = request.user.memberships.select_related(<span>\"organization\"</span>).first()\n <span>if</span> org_id:\n membership = request.user.memberships.filter(organization_id=org_id).first() <span>or</span> membership\n <span>if</span> membership:\n request.organization = membership.organization\n request.session[<span>\"active_org_id\"</span>] = <span>str</span>(membership.organization.id)\n <span>return</span> self.get_response(request)</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/context_processors.py</span>\n</div>\n<pre><span>def</span> <span>current_organization</span>(request):\n <span># makes {{ organization }} available in every template automatically</span>\n <span>return</span> {<span>\"organization\"</span>: getattr(request, <span>\"organization\"</span>, <span>None</span>)}</pre>\n</div>\n<div>Every product model (invoices, projects, tasks -- whatever your SaaS manages) should have a <code>ForeignKey(Organization)</code> and every queryset should filter by <code>request.organization</code>. That single discipline is what makes tenants properly isolated.</div>\n</section>\n<section class=\"step\" id=\"s9\">\n<div class=\"step-header\">\n<div class=\"step-badge\">09</div>\n<h2>Signup, login, and logout views</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Signup needs to do two things atomically: create the user <em>and</em> create their first organization. If either half fails alone, you get orphaned accounts -- so it all happens inside one transaction.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/forms.py</span>\n</div>\n<pre><span>from</span> django <span>import</span> forms\n<span>from</span> django.contrib.auth.forms <span>import</span> UserCreationForm\n<span>from</span> .models <span>import</span> User\n\n\n<span>class</span> <span>SignupForm</span>(UserCreationForm):\n company_name = forms.CharField(max_length=<span>120</span>, label=<span>\"Company name\"</span>)\n\n <span>class</span> <span>Meta</span>:\n model = User\n fields = [<span>\"email\"</span>, <span>\"password1\"</span>, <span>\"password2\"</span>, <span>\"company_name\"</span>]\n\n <span>def</span> <span>save</span>(self, commit=<span>True</span>):\n user = <span>super</span>().save(commit=<span>False</span>)\n user.username = self.cleaned_data[<span>\"email\"</span>]\n <span>if</span> commit:\n user.save()\n <span>return</span> user</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/views.py</span>\n</div>\n<pre><span>from</span> django.contrib.auth <span>import</span> login\n<span>from</span> django.contrib.auth.views <span>import</span> LoginView, LogoutView\n<span>from</span> django.db <span>import</span> transaction\n<span>from</span> django.shortcuts <span>import</span> redirect, render\n<span>from</span> django.utils.text <span>import</span> slugify\n<span>from</span> django.views <span>import</span> View\n\n<span>from</span> .forms <span>import</span> SignupForm\n<span>from</span> .models <span>import</span> Membership, Organization\n\n\n<span>class</span> <span>SignupView</span>(View):\n <span>def</span> <span>get</span>(self, request):\n <span>return</span> render(request, <span>\"accounts/signup.html\"</span>, {<span>\"form\"</span>: SignupForm()})\n\n <span>def</span> <span>post</span>(self, request):\n form = SignupForm(request.POST)\n <span>if</span> form.is_valid():\n <span>with</span> transaction.atomic():\n user = form.save()\n org = Organization.objects.create(\n name=form.cleaned_data[<span>\"company_name\"</span>],\n slug=slugify(form.cleaned_data[<span>\"company_name\"</span>]) + <span>\"-\"</span> + <span>str</span>(user.pk),\n )\n Membership.objects.create(user=user, organization=org, role=<span>\"owner\"</span>)\n login(request, user)\n <span>return</span> redirect(<span>\"dashboard:home\"</span>)\n <span>return</span> render(request, <span>\"accounts/signup.html\"</span>, {<span>\"form\"</span>: form})\n\n\n<span>class</span> <span>EmailLoginView</span>(LoginView):\n template_name = <span>\"accounts/login.html\"</span>\n\n\n<span>class</span> <span>EmailLogoutView</span>(LogoutView):\n <span>pass</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/urls.py</span>\n</div>\n<pre><span>from</span> django.urls <span>import</span> path\n<span>from</span> . <span>import</span> views\n\napp_name = <span>\"accounts\"</span>\n\nurlpatterns = [\n path(<span>\"signup/\"</span>, views.SignupView.as_view(), name=<span>\"signup\"</span>),\n path(<span>\"login/\"</span>, views.EmailLoginView.as_view(), name=<span>\"login\"</span>),\n path(<span>\"logout/\"</span>, views.EmailLogoutView.as_view(), name=<span>\"logout\"</span>),\n]</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Wrapping user + organization creation in <code>transaction.atomic()</code> means if the organization insert fails (e.g. a slug collision), the user row is rolled back too -- no half-created accounts.</div>\n</section>\n<section class=\"step\" id=\"s10\">\n<div class=\"step-header\">\n<div class=\"step-badge\">10</div>\n<h2>The base template</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Every page in the app -- marketing, auth, dashboard -- shares the same HTML skeleton, font loading, and CSS/JS includes. One <code>base.html</code> keeps that consistent and means a global change (like swapping a font) happens in one place.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/base.html</span>\n</div>\n<pre>&lt;<span>!DOCTYPE html</span>&gt;\n&lt;<span>html</span> <span>lang</span>=<span>\"en\"</span>&gt;\n&lt;<span>head</span>&gt;\n &lt;<span>meta</span> <span>charset</span>=<span>\"UTF-8\"</span>&gt;\n &lt;<span>meta</span> <span>name</span>=<span>\"viewport\"</span> <span>content</span>=<span>\"width=device-width, initial-scale=1.0\"</span>&gt;\n &lt;<span>title</span>&gt;{% <span>block</span> title %}SaaSDash{% <span>endblock</span> %}&lt;/<span>title</span>&gt;\n {% <span>load</span> static %}\n &lt;<span>link</span> <span>rel</span>=<span>\"stylesheet\"</span> <span>href</span>=<span>\"{% static 'css/base.css' %}\"</span>&gt;\n {% <span>block</span> extra_css %}{% <span>endblock</span> %}\n&lt;/<span>head</span>&gt;\n&lt;<span>body</span>&gt;\n {% <span>block</span> body %}{% <span>endblock</span> %}\n\n &lt;<span>script</span> <span>src</span>=<span>\"{% static 'js/base.js' %}\"</span>&gt;&lt;/<span>script</span>&gt;\n {% <span>block</span> extra_js %}{% <span>endblock</span> %}\n&lt;/<span>body</span>&gt;\n&lt;/<span>html</span>&gt;</pre>\n</div>\n<div>Each page extends this with <code>{% extends \"base.html\" %}</code> and fills in <code>{% block body %}</code>. Splitting <code>extra_css</code>/<code>extra_js</code> blocks lets the dashboard load a chart library only on pages that actually use it, instead of on every page including the marketing site.</div>\n<div class=\"step-body\">\n<p>Two more base files complete the public-facing shell: a marketing layout for logged-out visitors, and the dashboard layout for logged-in users (built fully in Step 11\u201312).</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/accounts/login.html</span>\n</div>\n<pre>{% <span>extends</span> \"base.html\" %}\n{% <span>block</span> title %}Log in -- SaaSDash{% <span>endblock</span> %}\n{% <span>block</span> body %}\n&lt;<span>div</span> <span>class</span>=<span>\"auth-screen\"</span>&gt;\n &lt;<span>div</span> <span>class</span>=<span>\"auth-card\"</span>&gt;\n &lt;<span>div</span> <span>class</span>=<span>\"auth-brand\"</span>&gt;SaaSDash&lt;/<span>div</span>&gt;\n &lt;<span>h1</span>&gt;Welcome back&lt;/<span>h1</span>&gt;\n &lt;<span>p</span> <span>class</span>=<span>\"auth-sub\"</span>&gt;Log in to your dashboard&lt;/<span>p</span>&gt;\n\n {% <span>if</span> form.errors %}\n &lt;<span>div</span> <span>class</span>=<span>\"auth-error\"</span>&gt;Your email or password is incorrect.&lt;/<span>div</span>&gt;\n {% <span>endif</span> %}\n\n &lt;<span>form</span> <span>method</span>=<span>\"post\"</span> <span>class</span>=<span>\"auth-form\"</span>&gt;\n {% <span>csrf_token</span> %}\n &lt;<span>label</span> <span>class</span>=<span>\"field-label\"</span>&gt;Email&lt;/<span>label</span>&gt;\n &lt;<span>input</span> <span>type</span>=<span>\"email\"</span> <span>name</span>=<span>\"username\"</span> <span>class</span>=<span>\"field-input\"</span> <span>required</span> <span>autofocus</span>&gt;\n\n &lt;<span>label</span> <span>class</span>=<span>\"field-label\"</span>&gt;Password&lt;/<span>label</span>&gt;\n &lt;<span>input</span> <span>type</span>=<span>\"password\"</span> <span>name</span>=<span>\"password\"</span> <span>class</span>=<span>\"field-input\"</span> <span>required</span>&gt;\n\n &lt;<span>button</span> <span>type</span>=<span>\"submit\"</span> <span>class</span>=<span>\"btn btn-primary btn-block\"</span>&gt;Log in&lt;/<span>button</span>&gt;\n &lt;/<span>form</span>&gt;\n\n &lt;<span>p</span> <span>class</span>=<span>\"auth-footer\"</span>&gt;\n Don't have an account? &lt;<span>a</span> <span>href</span>=<span>\"{% url 'accounts:signup' %}\"</span>&gt;Sign up&lt;/<span>a</span>&gt;\n &lt;/<span>p</span>&gt;\n &lt;/<span>div</span>&gt;\n&lt;/<span>div</span>&gt;\n{% <span>endblock</span> %}</pre>\n</div>\n<div class=\"tone-danger\"><strong>Watch out:</strong> the login field is named <code>name=\"username\"</code> even though it collects an email -- Django's built-in <code>AuthenticationForm</code> always names the identity field <code>username</code> regardless of <code>USERNAME_FIELD</code>. Renaming it breaks <code>LoginView</code> unless you also override the form.</div>\n</section>\n<section class=\"step\" id=\"s11\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">11</div>\n<h2>Dashboard layout CSS</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A dashboard's CSS is its own design system: fixed sidebar, sticky topbar, a content area that scrolls independently, and a consistent set of card/button/badge primitives reused on every screen. Defining these tokens once means new pages compose instead of reinventing styles.</div>\n<div class=\"step-body\">\n<p>Create <code>static/css/dashboard.css</code> -- loaded only on dashboard pages via the <code>extra_css</code> block, kept separate from <code>base.css</code> which covers the marketing site and auth screens.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">CSS</span>\n<span class=\"code-file\">static/css/dashboard.css</span>\n</div>\n<pre><span>/* ---- design tokens ---- */</span>\n<span>:root</span>{\n <span>--db-bg</span>: <span>#f7f8fa</span>;\n <span>--db-surface</span>: <span>#ffffff</span>;\n <span>--db-border</span>: <span>#e4e7ec</span>;\n <span>--db-text</span>: <span>#1a1d29</span>;\n <span>--db-muted</span>: <span>#6b7280</span>;\n <span>--db-primary</span>: <span>#4f46e5</span>;\n <span>--db-primary-dark</span>: <span>#4338ca</span>;\n <span>--db-success</span>: <span>#16a34a</span>;\n <span>--db-danger</span>: <span>#dc2626</span>;\n <span>--db-warning</span>: <span>#d97706</span>;\n <span>--db-radius</span>: <span>10px</span>;\n <span>--db-sidebar-w</span>: <span>240px</span>;\n <span>--db-topbar-h</span>: <span>64px</span>;\n <span>--db-shadow</span>: <span>0 1px 2px</span> rgba(<span>16,24,40</span>,.<span>06</span>);\n}\n\n<span>*</span>,<span>*::before</span>,<span>*::after</span>{<span>box-sizing</span>:<span>border-box</span>;}\n\n<span>.db-body</span>{\n <span>background</span>:<span>var</span>(--db-bg);\n <span>color</span>:<span>var</span>(--db-text);\n <span>font-family</span>:<span>'Inter',-apple-system,sans-serif</span>;\n <span>font-size</span>:<span>14px</span>;\n}\n\n<span>/* ---- layout shell ---- */</span>\n<span>.db-shell</span>{<span>display</span>:<span>flex</span>;<span>min-height</span>:<span>100vh</span>;}\n\n<span>.db-sidebar</span>{\n <span>width</span>:<span>var</span>(--db-sidebar-w);<span>flex-shrink</span>:<span>0</span>;\n <span>background</span>:<span>var</span>(--db-surface);\n <span>border-right</span>:<span>1px solid</span> <span>var</span>(--db-border);\n <span>position</span>:<span>fixed</span>;<span>top</span>:<span>0</span>;<span>left</span>:<span>0</span>;<span>bottom</span>:<span>0</span>;\n <span>display</span>:<span>flex</span>;<span>flex-direction</span>:<span>column</span>;\n <span>transition</span>:<span>transform .2s ease</span>;\n <span>z-index</span>:<span>40</span>;\n}\n\n<span>.db-main</span>{\n <span>margin-left</span>:<span>var</span>(--db-sidebar-w);\n <span>flex</span>:<span>1</span>;<span>min-width</span>:<span>0</span>;\n <span>display</span>:<span>flex</span>;<span>flex-direction</span>:<span>column</span>;\n}\n\n<span>.db-content</span>{\n <span>padding</span>:<span>28px 32px 60px</span>;\n <span>max-width</span>:<span>1320px</span>;\n <span>width</span>:<span>100%</span>;\n}\n\n<span>/* ---- responsive: collapse sidebar under 960px ---- */</span>\n<span>@media</span>(<span>max-width</span>:<span>960px</span>){\n <span>.db-sidebar</span>{<span>transform</span>:<span>translateX(-100%)</span>;}\n <span>.db-sidebar.is-open</span>{<span>transform</span>:<span>translateX(0)</span>;}\n <span>.db-main</span>{<span>margin-left</span>:<span>0</span>;}\n <span>.db-content</span>{<span>padding</span>:<span>20px 16px 48px</span>;}\n}\n\n<span>/* ---- reusable primitives used by every dashboard screen ---- */</span>\n<span>.btn</span>{\n <span>display</span>:<span>inline-flex</span>;<span>align-items</span>:<span>center</span>;<span>gap</span>:<span>6px</span>;\n <span>padding</span>:<span>9px 16px</span>;<span>border-radius</span>:<span>8px</span>;\n <span>font-size</span>:<span>13.5px</span>;<span>font-weight</span>:<span>600</span>;\n <span>border</span>:<span>1px solid transparent</span>;<span>cursor</span>:<span>pointer</span>;\n <span>transition</span>:<span>background .15s,border-color .15s,transform .1s</span>;\n}\n<span>.btn:active</span>{<span>transform</span>:<span>scale(.98)</span>;}\n<span>.btn-primary</span>{<span>background</span>:<span>var</span>(--db-primary);<span>color</span>:<span>#fff</span>;}\n<span>.btn-primary:hover</span>{<span>background</span>:<span>var</span>(--db-primary-dark);}\n<span>.btn-secondary</span>{<span>background</span>:<span>var</span>(--db-surface);<span>color</span>:<span>var</span>(--db-text);<span>border-color</span>:<span>var</span>(--db-border);}\n<span>.btn-secondary:hover</span>{<span>background</span>:<span>var</span>(--db-bg);}\n<span>.btn-danger</span>{<span>background</span>:rgba(<span>220,38,38</span>,.<span>08</span>);<span>color</span>:<span>var</span>(--db-danger);}\n<span>.btn-block</span>{<span>width</span>:<span>100%</span>;<span>justify-content</span>:<span>center</span>;}\n\n<span>.card</span>{\n <span>background</span>:<span>var</span>(--db-surface);\n <span>border</span>:<span>1px solid</span> <span>var</span>(--db-border);\n <span>border-radius</span>:<span>var</span>(--db-radius);\n <span>box-shadow</span>:<span>var</span>(--db-shadow);\n}\n\n<span>.badge</span>{\n <span>display</span>:<span>inline-flex</span>;<span>align-items</span>:<span>center</span>;<span>gap</span>:<span>5px</span>;\n <span>padding</span>:<span>3px 10px</span>;<span>border-radius</span>:<span>100px</span>;\n <span>font-size</span>:<span>11.5px</span>;<span>font-weight</span>:<span>600</span>;\n}\n<span>.badge-success</span>{<span>background</span>:rgba(<span>22,163,74</span>,.<span>1</span>);<span>color</span>:<span>var</span>(--db-success);}\n<span>.badge-warning</span>{<span>background</span>:rgba(<span>217,119,6</span>,.<span>1</span>);<span>color</span>:<span>var</span>(--db-warning);}\n<span>.badge-danger</span>{<span>background</span>:rgba(<span>220,38,38</span>,.<span>1</span>);<span>color</span>:<span>var</span>(--db-danger);}\n<span>.badge-neutral</span>{<span>background</span>:<span>var</span>(--db-bg);<span>color</span>:<span>var</span>(--db-muted);}</pre>\n</div>\n<div>All border placement in this guide follows one rule: <strong>every bordered box defines its own four borders or shorthand <code>border</code> property; nothing relies on a neighbor's border for a shared edge.</strong> That avoids the classic \"double border\" or \"missing border\" bug you get from collapsing margins between adjacent cards.</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Keep dashboard tokens (<code>--db-*</code>) namespaced separately from the marketing site's tokens in <code>base.css</code>. It stops a future redesign of one from silently breaking the other.</div>\n</section>\n<section class=\"step\" id=\"s12\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">12</div>\n<h2>Sidebar &amp; topbar markup</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>The sidebar and topbar are the two elements present on every dashboard page. Building them as Django <strong>includes</strong> means a new nav item or a new topbar action is a one-file change, not a find-and-replace across every template.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/dashboard/_sidebar.html</span>\n</div>\n<pre>&lt;<span>aside</span> <span>class</span>=<span>\"db-sidebar\"</span> <span>id</span>=<span>\"dbSidebar\"</span>&gt;\n &lt;<span>div</span> <span>class</span>=<span>\"db-sidebar-brand\"</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"db-logo-dot\"</span>&gt;&lt;/<span>span</span>&gt;\n SaaSDash\n &lt;/<span>div</span>&gt;\n\n &lt;<span>nav</span> <span>class</span>=<span>\"db-nav\"</span>&gt;\n &lt;<span>a</span> <span>href</span>=<span>\"{% url 'dashboard:home' %}\"</span>\n <span>class</span>=<span>\"db-nav-link {% if request.resolver_match.url_name == 'home' %}active{% endif %}\"</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"db-nav-icon\"</span>&gt;\u25a3&lt;/<span>span</span>&gt; Overview\n &lt;/<span>a</span>&gt;\n &lt;<span>a</span> <span>href</span>=<span>\"{% url 'dashboard:projects' %}\"</span>\n <span>class</span>=<span>\"db-nav-link {% if request.resolver_match.url_name == 'projects' %}active{% endif %}\"</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"db-nav-icon\"</span>&gt;&lt;/<span>span</span>&gt; Projects\n &lt;/<span>a</span>&gt;\n &lt;<span>a</span> <span>href</span>=<span>\"{% url 'dashboard:team' %}\"</span>\n <span>class</span>=<span>\"db-nav-link {% if request.resolver_match.url_name == 'team' %}active{% endif %}\"</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"db-nav-icon\"</span>&gt;&lt;/<span>span</span>&gt; Team\n &lt;/<span>a</span>&gt;\n &lt;<span>a</span> <span>href</span>=<span>\"{% url 'dashboard:billing' %}\"</span>\n <span>class</span>=<span>\"db-nav-link {% if request.resolver_match.url_name == 'billing' %}active{% endif %}\"</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"db-nav-icon\"</span>&gt;\u25c6&lt;/<span>span</span>&gt; Billing\n &lt;/<span>a</span>&gt;\n &lt;<span>a</span> <span>href</span>=<span>\"{% url 'dashboard:settings' %}\"</span>\n <span>class</span>=<span>\"db-nav-link {% if request.resolver_match.url_name == 'settings' %}active{% endif %}\"</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"db-nav-icon\"</span>&gt;&lt;/<span>span</span>&gt; Settings\n &lt;/<span>a</span>&gt;\n &lt;/<span>nav</span>&gt;\n\n &lt;<span>div</span> <span>class</span>=<span>\"db-sidebar-footer\"</span>&gt;\n &lt;<span>div</span> <span>class</span>=<span>\"db-org-pill\"</span>&gt;{{ organization.name }}&lt;/<span>div</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"badge badge-neutral\"</span>&gt;{{ organization.get_plan_display }} plan&lt;/<span>span</span>&gt;\n &lt;/<span>div</span>&gt;\n&lt;/<span>aside</span>&gt;</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/dashboard/_topbar.html</span>\n</div>\n<pre>&lt;<span>header</span> <span>class</span>=<span>\"db-topbar\"</span>&gt;\n &lt;<span>button</span> <span>class</span>=<span>\"db-burger\"</span> <span>id</span>=<span>\"dbBurger\"</span> <span>aria-label</span>=<span>\"Toggle menu\"</span>&gt;&lt;/<span>button</span>&gt;\n &lt;<span>h1</span> <span>class</span>=<span>\"db-page-title\"</span>&gt;{% <span>block</span> page_title %}Overview{% <span>endblock</span> %}&lt;/<span>h1</span>&gt;\n\n &lt;<span>div</span> <span>class</span>=<span>\"db-topbar-actions\"</span>&gt;\n &lt;<span>div</span> <span>class</span>=<span>\"db-avatar-menu\"</span> <span>id</span>=<span>\"dbAvatarMenu\"</span>&gt;\n &lt;<span>button</span> <span>class</span>=<span>\"db-avatar\"</span> <span>id</span>=<span>\"dbAvatarBtn\"</span>&gt;{{ request.user.email|first|upper }}&lt;/<span>button</span>&gt;\n &lt;<span>div</span> <span>class</span>=<span>\"db-dropdown\"</span> <span>id</span>=<span>\"dbDropdown\"</span>&gt;\n &lt;<span>div</span> <span>class</span>=<span>\"db-dropdown-email\"</span>&gt;{{ request.user.email }}&lt;/<span>div</span>&gt;\n &lt;<span>a</span> <span>href</span>=<span>\"{% url 'dashboard:settings' %}\"</span>&gt;Account settings&lt;/<span>a</span>&gt;\n &lt;<span>a</span> <span>href</span>=<span>\"{% url 'accounts:logout' %}\"</span>&gt;Log out&lt;/<span>a</span>&gt;\n &lt;/<span>div</span>&gt;\n &lt;/<span>div</span>&gt;\n &lt;/<span>div</span>&gt;\n&lt;/<span>header</span>&gt;</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">CSS</span>\n<span class=\"code-file\">static/css/dashboard.css (continued)</span>\n</div>\n<pre><span>.db-sidebar-brand</span>{\n <span>display</span>:<span>flex</span>;<span>align-items</span>:<span>center</span>;<span>gap</span>:<span>10px</span>;\n <span>padding</span>:<span>20px 22px</span>;<span>font-weight</span>:<span>700</span>;<span>font-size</span>:<span>15px</span>;\n <span>border-bottom</span>:<span>1px solid</span> <span>var</span>(--db-border);\n}\n<span>.db-logo-dot</span>{<span>width</span>:<span>10px</span>;<span>height</span>:<span>10px</span>;<span>border-radius</span>:<span>3px</span>;<span>background</span>:<span>var</span>(--db-primary);}\n\n<span>.db-nav</span>{<span>flex</span>:<span>1</span>;<span>padding</span>:<span>12px</span>;<span>display</span>:<span>flex</span>;<span>flex-direction</span>:<span>column</span>;<span>gap</span>:<span>2px</span>;}\n<span>.db-nav-link</span>{\n <span>display</span>:<span>flex</span>;<span>align-items</span>:<span>center</span>;<span>gap</span>:<span>10px</span>;\n <span>padding</span>:<span>9px 12px</span>;<span>border-radius</span>:<span>7px</span>;\n <span>color</span>:<span>var</span>(--db-muted);<span>text-decoration</span>:<span>none</span>;<span>font-weight</span>:<span>500</span>;\n <span>transition</span>:<span>background .15s,color .15s</span>;\n}\n<span>.db-nav-link:hover</span>{<span>background</span>:<span>var</span>(--db-bg);<span>color</span>:<span>var</span>(--db-text);}\n<span>.db-nav-link.active</span>{<span>background</span>:rgba(<span>79,70,229</span>,.<span>08</span>);<span>color</span>:<span>var</span>(--db-primary);}\n<span>.db-nav-icon</span>{<span>width</span>:<span>18px</span>;<span>text-align</span>:<span>center</span>;}\n\n<span>.db-sidebar-footer</span>{\n <span>padding</span>:<span>16px</span>;<span>border-top</span>:<span>1px solid</span> <span>var</span>(--db-border);\n <span>display</span>:<span>flex</span>;<span>flex-direction</span>:<span>column</span>;<span>gap</span>:<span>8px</span>;\n}\n<span>.db-org-pill</span>{<span>font-weight</span>:<span>600</span>;<span>font-size</span>:<span>13px</span>;}\n\n<span>.db-topbar</span>{\n <span>height</span>:<span>var</span>(--db-topbar-h);<span>flex-shrink</span>:<span>0</span>;\n <span>display</span>:<span>flex</span>;<span>align-items</span>:<span>center</span>;<span>gap</span>:<span>14px</span>;\n <span>padding</span>:<span>0 24px</span>;<span>background</span>:<span>var</span>(--db-surface);\n <span>border-bottom</span>:<span>1px solid</span> <span>var</span>(--db-border);\n <span>position</span>:<span>sticky</span>;<span>top</span>:<span>0</span>;<span>z-index</span>:<span>30</span>;\n}\n<span>.db-burger</span>{<span>display</span>:<span>none</span>;<span>background</span>:<span>none</span>;<span>border</span>:<span>none</span>;<span>font-size</span>:<span>20px</span>;<span>cursor</span>:<span>pointer</span>;}\n<span>.db-page-title</span>{<span>font-size</span>:<span>17px</span>;<span>font-weight</span>:<span>700</span>;<span>flex</span>:<span>1</span>;}\n<span>.db-topbar-actions</span>{<span>display</span>:<span>flex</span>;<span>align-items</span>:<span>center</span>;<span>gap</span>:<span>12px</span>;}\n\n<span>.db-avatar-menu</span>{<span>position</span>:<span>relative</span>;}\n<span>.db-avatar</span>{\n <span>width</span>:<span>34px</span>;<span>height</span>:<span>34px</span>;<span>border-radius</span>:<span>50%</span>;\n <span>background</span>:<span>var</span>(--db-primary);<span>color</span>:<span>#fff</span>;<span>border</span>:<span>none</span>;\n <span>font-weight</span>:<span>600</span>;<span>cursor</span>:<span>pointer</span>;\n}\n<span>.db-dropdown</span>{\n <span>position</span>:<span>absolute</span>;<span>top</span>:<span>calc(100% + 8px)</span>;<span>right</span>:<span>0</span>;\n <span>background</span>:<span>var</span>(--db-surface);<span>border</span>:<span>1px solid</span> <span>var</span>(--db-border);\n <span>border-radius</span>:<span>10px</span>;<span>box-shadow</span>:<span>0 8px 24px</span> rgba(<span>16,24,40</span>,.<span>10</span>);\n <span>min-width</span>:<span>200px</span>;<span>padding</span>:<span>6px</span>;\n <span>opacity</span>:<span>0</span>;<span>visibility</span>:<span>hidden</span>;<span>transform</span>:<span>translateY(-6px)</span>;\n <span>transition</span>:<span>opacity .15s,transform .15s,visibility .15s</span>;\n <span>z-index</span>:<span>50</span>;\n}\n<span>.db-dropdown.is-open</span>{<span>opacity</span>:<span>1</span>;<span>visibility</span>:<span>visible</span>;<span>transform</span>:<span>translateY(0)</span>;}\n<span>.db-dropdown-email</span>{<span>padding</span>:<span>8px 10px</span>;<span>font-size</span>:<span>12px</span>;<span>color</span>:<span>var</span>(--db-muted);<span>border-bottom</span>:<span>1px solid</span> <span>var</span>(--db-border);<span>margin-bottom</span>:<span>4px</span>;}\n<span>.db-dropdown a</span>{<span>display</span>:<span>block</span>;<span>padding</span>:<span>8px 10px</span>;<span>border-radius</span>:<span>6px</span>;<span>color</span>:<span>var</span>(--db-text);<span>text-decoration</span>:<span>none</span>;<span>font-size</span>:<span>13px</span>;}\n<span>.db-dropdown a:hover</span>{<span>background</span>:<span>var</span>(--db-bg);}</pre>\n</div>\n<div>Notice the topbar uses <code>border-bottom</code> and the sidebar uses <code>border-right</code> -- each owns exactly one shared edge, so resizing one never shifts or doubles the other's line. This is the border-placement convention referenced in Step 11.</div>\n</section>\n<section class=\"step\" id=\"s13\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">13</div>\n<h2>Stat cards and a chart</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>The overview page is the first thing every user sees after login. Stat cards answer \"is everything OK?\" at a glance; a chart answers \"what's the trend?\" -- together they're the minimum viable dashboard home page.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/dashboard/home.html</span>\n</div>\n<pre>{% <span>extends</span> \"dashboard/_layout.html\" %}\n{% <span>block</span> page_title %}Overview{% <span>endblock</span> %}\n\n{% <span>block</span> dashboard_content %}\n&lt;<span>div</span> <span>class</span>=<span>\"stat-grid\"</span>&gt;\n &lt;<span>div</span> <span>class</span>=<span>\"card stat-card\"</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"stat-label\"</span>&gt;Active projects&lt;/<span>span</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"stat-value\"</span>&gt;{{ stats.active_projects }}&lt;/<span>span</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"stat-delta up\"</span>&gt;\u2191 {{ stats.projects_delta }}% vs last month&lt;/<span>span</span>&gt;\n &lt;/<span>div</span>&gt;\n &lt;<span>div</span> <span>class</span>=<span>\"card stat-card\"</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"stat-label\"</span>&gt;Team members&lt;/<span>span</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"stat-value\"</span>&gt;{{ stats.member_count }}&lt;/<span>span</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"stat-delta neutral\"</span>&gt;No change&lt;/<span>span</span>&gt;\n &lt;/<span>div</span>&gt;\n &lt;<span>div</span> <span>class</span>=<span>\"card stat-card\"</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"stat-label\"</span>&gt;MRR&lt;/<span>span</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"stat-value\"</span>&gt;${{ stats.mrr }}&lt;/<span>span</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"stat-delta up\"</span>&gt;\u2191 {{ stats.mrr_delta }}%&lt;/<span>span</span>&gt;\n &lt;/<span>div</span>&gt;\n &lt;<span>div</span> <span>class</span>=<span>\"card stat-card\"</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"stat-label\"</span>&gt;Open tickets&lt;/<span>span</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"stat-value\"</span>&gt;{{ stats.open_tickets }}&lt;/<span>span</span>&gt;\n &lt;<span>span</span> <span>class</span>=<span>\"stat-delta down\"</span>&gt;\u2193 {{ stats.tickets_delta }}%&lt;/<span>span</span>&gt;\n &lt;/<span>div</span>&gt;\n&lt;/<span>div</span>&gt;\n\n&lt;<span>div</span> <span>class</span>=<span>\"card chart-card\"</span>&gt;\n &lt;<span>div</span> <span>class</span>=<span>\"card-header\"</span>&gt;\n &lt;<span>h2</span> <span>class</span>=<span>\"card-title\"</span>&gt;Usage this week&lt;/<span>h2</span>&gt;\n &lt;/<span>div</span>&gt;\n &lt;<span>svg</span> <span>class</span>=<span>\"bar-chart\"</span> <span>id</span>=<span>\"usageChart\"</span> <span>viewBox</span>=<span>\"0 0 700 220\"</span>\n <span>data-values</span>=<span>\"{{ stats.daily_usage }}\"</span>&gt;&lt;/<span>svg</span>&gt;\n&lt;/<span>div</span>&gt;\n{% <span>endblock</span> %}</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">CSS</span>\n<span class=\"code-file\">static/css/dashboard.css (continued)</span>\n</div>\n<pre><span>.stat-grid</span>{\n <span>display</span>:<span>grid</span>;<span>grid-template-columns</span>:<span>repeat(4,1fr)</span>;<span>gap</span>:<span>16px</span>;<span>margin-bottom</span>:<span>20px</span>;\n}\n<span>.stat-card</span>{<span>padding</span>:<span>18px 20px</span>;<span>display</span>:<span>flex</span>;<span>flex-direction</span>:<span>column</span>;<span>gap</span>:<span>6px</span>;}\n<span>.stat-label</span>{<span>font-size</span>:<span>12.5px</span>;<span>color</span>:<span>var</span>(--db-muted);<span>font-weight</span>:<span>600</span>;}\n<span>.stat-value</span>{<span>font-size</span>:<span>26px</span>;<span>font-weight</span>:<span>700</span>;<span>letter-spacing</span>:<span>-.01em</span>;}\n<span>.stat-delta</span>{<span>font-size</span>:<span>12px</span>;<span>font-weight</span>:<span>600</span>;}\n<span>.stat-delta.up</span>{<span>color</span>:<span>var</span>(--db-success);}\n<span>.stat-delta.down</span>{<span>color</span>:<span>var</span>(--db-danger);}\n<span>.stat-delta.neutral</span>{<span>color</span>:<span>var</span>(--db-muted);}\n\n<span>.chart-card</span>{<span>padding</span>:<span>20px</span>;}\n<span>.card-header</span>{<span>display</span>:<span>flex</span>;<span>align-items</span>:<span>center</span>;<span>justify-content</span>:<span>space-between</span>;<span>margin-bottom</span>:<span>14px</span>;}\n<span>.card-title</span>{<span>font-size</span>:<span>14.5px</span>;<span>font-weight</span>:<span>700</span>;}\n<span>.bar-chart</span>{<span>width</span>:<span>100%</span>;<span>height</span>:<span>220px</span>;<span>display</span>:<span>block</span>;}\n<span>.bar-chart rect</span>{<span>fill</span>:<span>var</span>(--db-primary);<span>opacity</span>:.<span>85</span>;<span>transition</span>:<span>opacity .15s</span>;}\n<span>.bar-chart rect:hover</span>{<span>opacity</span>:<span>1</span>;}\n<span>.bar-chart text</span>{<span>fill</span>:<span>var</span>(--db-muted);<span>font-size</span>:<span>10px</span>;<span>font-family</span>:<span>'Inter',sans-serif</span>;}\n\n<span>@media</span>(<span>max-width</span>:<span>1100px</span>){<span>.stat-grid</span>{<span>grid-template-columns</span>:<span>repeat(2,1fr)</span>;}}\n<span>@media</span>(<span>max-width</span>:<span>560px</span>){<span>.stat-grid</span>{<span>grid-template-columns</span>:<span>1fr</span>;}}</pre>\n</div>\n<div>The chart is plain SVG built by JS in Step 16, not a charting library -- zero dependencies, no build step, and it's themeable with the same CSS variables as the rest of the dashboard. Swap in Chart.js or Recharts later if you need tooltips, zoom, or animated transitions.</div>\n</section>\n<section class=\"step\" id=\"s14\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">14</div>\n<h2>Data tables</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Tables are where users spend most of their time in a B2B dashboard. Getting row hover states, status badges, and empty states right here pays off on every list screen in the product -- projects, team members, invoices.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/dashboard/projects.html</span>\n</div>\n<pre>{% <span>extends</span> \"dashboard/_layout.html\" %}\n{% <span>block</span> page_title %}Projects{% <span>endblock</span> %}\n\n{% <span>block</span> dashboard_content %}\n&lt;<span>div</span> <span>class</span>=<span>\"card-header\"</span> <span>style</span>=<span>\"margin-bottom:16px\"</span>&gt;\n &lt;<span>h2</span> <span>class</span>=<span>\"card-title\"</span>&gt;All projects&lt;/<span>h2</span>&gt;\n &lt;<span>button</span> <span>class</span>=<span>\"btn btn-primary\"</span> <span>data-modal-target</span>=<span>\"newProjectModal\"</span>&gt;+ New project&lt;/<span>button</span>&gt;\n&lt;/<span>div</span>&gt;\n\n&lt;<span>div</span> <span>class</span>=<span>\"card table-card\"</span>&gt;\n {% <span>if</span> projects %}\n &lt;<span>table</span> <span>class</span>=<span>\"db-table\"</span>&gt;\n &lt;<span>thead</span>&gt;\n &lt;<span>tr</span>&gt;\n &lt;<span>th</span>&gt;Name&lt;/<span>th</span>&gt;&lt;<span>th</span>&gt;Status&lt;/<span>th</span>&gt;&lt;<span>th</span>&gt;Owner&lt;/<span>th</span>&gt;&lt;<span>th</span>&gt;Updated&lt;/<span>th</span>&gt;&lt;<span>th</span>&gt;&lt;/<span>th</span>&gt;\n &lt;/<span>tr</span>&gt;\n &lt;/<span>thead</span>&gt;\n &lt;<span>tbody</span>&gt;\n {% <span>for</span> p <span>in</span> projects %}\n &lt;<span>tr</span>&gt;\n &lt;<span>td</span>&gt;&lt;<span>strong</span>&gt;{{ p.name }}&lt;/<span>strong</span>&gt;&lt;/<span>td</span>&gt;\n &lt;<span>td</span>&gt;&lt;<span>span</span> <span>class</span>=<span>\"badge badge-{{ p.status_color }}\"</span>&gt;{{ p.get_status_display }}&lt;/<span>span</span>&gt;&lt;/<span>td</span>&gt;\n &lt;<span>td</span>&gt;{{ p.owner.email }}&lt;/<span>td</span>&gt;\n &lt;<span>td</span>&gt;{{ p.updated_at|timesince }} ago&lt;/<span>td</span>&gt;\n &lt;<span>td</span> <span>class</span>=<span>\"table-actions\"</span>&gt;\n &lt;<span>a</span> <span>href</span>=<span>\"{% url 'dashboard:project_detail' p.pk %}\"</span>&gt;View&lt;/<span>a</span>&gt;\n &lt;/<span>td</span>&gt;\n &lt;/<span>tr</span>&gt;\n {% <span>endfor</span> %}\n &lt;/<span>tbody</span>&gt;\n &lt;/<span>table</span>&gt;\n {% <span>else</span> %}\n &lt;<span>div</span> <span>class</span>=<span>\"empty-state\"</span>&gt;\n &lt;<span>p</span>&gt;No projects yet&lt;/<span>p</span>&gt;\n &lt;<span>span</span>&gt;Create your first project to start tracking work.&lt;/<span>span</span>&gt;\n &lt;/<span>div</span>&gt;\n {% <span>endif</span> %}\n&lt;/<span>div</span>&gt;\n{% <span>endblock</span> %}</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">CSS</span>\n<span class=\"code-file\">static/css/dashboard.css (continued)</span>\n</div>\n<pre><span>.table-card</span>{<span>overflow</span>:<span>hidden</span>;}\n<span>.db-table</span>{<span>width</span>:<span>100%</span>;<span>border-collapse</span>:<span>collapse</span>;<span>font-size</span>:<span>13.5px</span>;}\n<span>.db-table thead th</span>{\n <span>text-align</span>:<span>left</span>;<span>padding</span>:<span>12px 20px</span>;\n <span>background</span>:<span>var</span>(--db-bg);<span>color</span>:<span>var</span>(--db-muted);\n <span>font-weight</span>:<span>600</span>;<span>font-size</span>:<span>12px</span>;<span>text-transform</span>:<span>uppercase</span>;<span>letter-spacing</span>:.<span>04em</span>;\n <span>border-bottom</span>:<span>1px solid</span> <span>var</span>(--db-border);\n}\n<span>.db-table tbody td</span>{<span>padding</span>:<span>14px 20px</span>;<span>border-bottom</span>:<span>1px solid</span> <span>var</span>(--db-border);<span>color</span>:<span>var</span>(--db-text);}\n<span>.db-table tbody tr:last-child td</span>{<span>border-bottom</span>:<span>none</span>;}\n<span>.db-table tbody tr:hover</span>{<span>background</span>:<span>var</span>(--db-bg);}\n<span>.table-actions a</span>{<span>color</span>:<span>var</span>(--db-primary);<span>font-weight</span>:<span>600</span>;<span>text-decoration</span>:<span>none</span>;<span>font-size</span>:<span>12.5px</span>;}\n\n<span>.empty-state</span>{<span>padding</span>:<span>60px 20px</span>;<span>text-align</span>:<span>center</span>;}\n<span>.empty-state p</span>{<span>font-weight</span>:<span>600</span>;<span>margin-bottom</span>:<span>4px</span>;}\n<span>.empty-state span</span>{<span>color</span>:<span>var</span>(--db-muted);<span>font-size</span>:<span>13px</span>;}</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> for tables with hundreds of rows, paginate server-side with Django's <code>Paginator</code> rather than loading everything and hiding rows with CSS -- it keeps the page fast and the HTML small.</div>\n</section>\n<section class=\"step\" id=\"s15\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">15</div>\n<h2>Forms and a modal</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>\"New project,\" \"invite teammate,\" \"edit settings\" -- nearly every dashboard action is a small form. A reusable modal component means you write that pattern once instead of duplicating popup logic per feature.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/dashboard/_new_project_modal.html</span>\n</div>\n<pre>&lt;<span>div</span> <span>class</span>=<span>\"db-modal-backdrop\"</span> <span>id</span>=<span>\"newProjectModal\"</span>&gt;\n &lt;<span>div</span> <span>class</span>=<span>\"db-modal\"</span>&gt;\n &lt;<span>div</span> <span>class</span>=<span>\"db-modal-header\"</span>&gt;\n &lt;<span>h3</span>&gt;New project&lt;/<span>h3</span>&gt;\n &lt;<span>button</span> <span>class</span>=<span>\"db-modal-close\"</span> <span>data-modal-close</span>&gt;&lt;/<span>button</span>&gt;\n &lt;/<span>div</span>&gt;\n &lt;<span>form</span> <span>method</span>=<span>\"post\"</span> <span>action</span>=<span>\"{% url 'dashboard:project_create' %}\"</span>&gt;\n {% <span>csrf_token</span> %}\n &lt;<span>div</span> <span>class</span>=<span>\"db-modal-body\"</span>&gt;\n &lt;<span>label</span> <span>class</span>=<span>\"field-label\"</span>&gt;Project name&lt;/<span>label</span>&gt;\n &lt;<span>input</span> <span>type</span>=<span>\"text\"</span> <span>name</span>=<span>\"name\"</span> <span>class</span>=<span>\"field-input\"</span> <span>required</span>&gt;\n\n &lt;<span>label</span> <span>class</span>=<span>\"field-label\"</span>&gt;Description&lt;/<span>label</span>&gt;\n &lt;<span>textarea</span> <span>name</span>=<span>\"description\"</span> <span>class</span>=<span>\"field-input\"</span> <span>rows</span>=<span>\"3\"</span>&gt;&lt;/<span>textarea</span>&gt;\n &lt;/<span>div</span>&gt;\n &lt;<span>div</span> <span>class</span>=<span>\"db-modal-footer\"</span>&gt;\n &lt;<span>button</span> <span>type</span>=<span>\"button\"</span> <span>class</span>=<span>\"btn btn-secondary\"</span> <span>data-modal-close</span>&gt;Cancel&lt;/<span>button</span>&gt;\n &lt;<span>button</span> <span>type</span>=<span>\"submit\"</span> <span>class</span>=<span>\"btn btn-primary\"</span>&gt;Create project&lt;/<span>button</span>&gt;\n &lt;/<span>div</span>&gt;\n &lt;/<span>form</span>&gt;\n &lt;/<span>div</span>&gt;\n&lt;/<span>div</span>&gt;</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">CSS</span>\n<span class=\"code-file\">static/css/dashboard.css (continued)</span>\n</div>\n<pre><span>.field-label</span>{<span>display</span>:<span>block</span>;<span>font-size</span>:<span>12.5px</span>;<span>font-weight</span>:<span>600</span>;<span>margin</span>:<span>14px 0 6px</span>;}\n<span>.field-input</span>{\n <span>width</span>:<span>100%</span>;<span>padding</span>:<span>10px 12px</span>;<span>font-size</span>:<span>13.5px</span>;\n <span>border</span>:<span>1px solid</span> <span>var</span>(--db-border);<span>border-radius</span>:<span>7px</span>;\n <span>background</span>:<span>var</span>(--db-surface);<span>color</span>:<span>var</span>(--db-text);\n <span>transition</span>:<span>border-color .15s,box-shadow .15s</span>;\n}\n<span>.field-input:focus</span>{\n <span>outline</span>:<span>none</span>;<span>border-color</span>:<span>var</span>(--db-primary);\n <span>box-shadow</span>:<span>0 0 0 3px</span> rgba(<span>79,70,229</span>,.<span>12</span>);\n}\n\n<span>.db-modal-backdrop</span>{\n <span>position</span>:<span>fixed</span>;<span>inset</span>:<span>0</span>;<span>background</span>:rgba(<span>16,24,40</span>,.<span>45</span>);\n <span>display</span>:<span>flex</span>;<span>align-items</span>:<span>center</span>;<span>justify-content</span>:<span>center</span>;\n <span>opacity</span>:<span>0</span>;<span>visibility</span>:<span>hidden</span>;<span>transition</span>:<span>opacity .15s,visibility .15s</span>;\n <span>z-index</span>:<span>100</span>;<span>padding</span>:<span>20px</span>;\n}\n<span>.db-modal-backdrop.is-open</span>{<span>opacity</span>:<span>1</span>;<span>visibility</span>:<span>visible</span>;}\n<span>.db-modal</span>{\n <span>background</span>:<span>var</span>(--db-surface);<span>border-radius</span>:<span>12px</span>;\n <span>width</span>:<span>440px</span>;<span>max-width</span>:<span>100%</span>;\n <span>box-shadow</span>:<span>0 24px 48px</span> rgba(<span>16,24,40</span>,.<span>18</span>);\n <span>transform</span>:<span>translateY(-10px)</span>;<span>transition</span>:<span>transform .15s</span>;\n}\n<span>.db-modal-backdrop.is-open .db-modal</span>{<span>transform</span>:<span>translateY(0)</span>;}\n<span>.db-modal-header</span>{\n <span>display</span>:<span>flex</span>;<span>align-items</span>:<span>center</span>;<span>justify-content</span>:<span>space-between</span>;\n <span>padding</span>:<span>16px 20px</span>;<span>border-bottom</span>:<span>1px solid</span> <span>var</span>(--db-border);\n}\n<span>.db-modal-header h3</span>{<span>font-size</span>:<span>15px</span>;<span>font-weight</span>:<span>700</span>;}\n<span>.db-modal-close</span>{<span>background</span>:<span>none</span>;<span>border</span>:<span>none</span>;<span>cursor</span>:<span>pointer</span>;<span>font-size</span>:<span>14px</span>;<span>color</span>:<span>var</span>(--db-muted);}\n<span>.db-modal-body</span>{<span>padding</span>:<span>4px 20px 20px</span>;}\n<span>.db-modal-footer</span>{\n <span>display</span>:<span>flex</span>;<span>justify-content</span>:<span>flex-end</span>;<span>gap</span>:<span>10px</span>;\n <span>padding</span>:<span>14px 20px</span>;<span>border-top</span>:<span>1px solid</span> <span>var</span>(--db-border);\n}</pre>\n</div>\n<div class=\"tone-danger\"><strong>Watch out:</strong> the modal HTML is included once in <code>_layout.html</code>, not per-button. Duplicate <code>id</code> attributes on a page are invalid HTML and only the first match will ever respond to JS selectors.</div>\n</section>\n<section class=\"step\" id=\"s16\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">16</div>\n<h2>JS interactivity</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Sidebar toggling, dropdown menus, modals, and the bar chart all need a small amount of vanilla JS. Writing it as independent, event-delegated functions means you can add a tenth modal later without touching this file.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">JavaScript</span>\n<span class=\"code-file\">static/js/dashboard.js</span>\n</div>\n<pre><span>// ---- mobile sidebar toggle ----</span>\n<span>const</span> burger = document.getElementById(<span>'dbBurger'</span>);\n<span>const</span> sidebar = document.getElementById(<span>'dbSidebar'</span>);\n<span>if</span> (burger &amp;&amp; sidebar) {\n burger.addEventListener(<span>'click'</span>, () =&gt; sidebar.classList.toggle(<span>'is-open'</span>));\n}\n\n<span>// ---- avatar dropdown ----</span>\n<span>const</span> avatarBtn = document.getElementById(<span>'dbAvatarBtn'</span>);\n<span>const</span> dropdown = document.getElementById(<span>'dbDropdown'</span>);\n<span>if</span> (avatarBtn &amp;&amp; dropdown) {\n avatarBtn.addEventListener(<span>'click'</span>, (e) =&gt; {\n e.stopPropagation();\n dropdown.classList.toggle(<span>'is-open'</span>);\n });\n document.addEventListener(<span>'click'</span>, () =&gt; dropdown.classList.remove(<span>'is-open'</span>));\n}\n\n<span>// ---- generic modal open/close, works for any number of modals ----</span>\ndocument.querySelectorAll(<span>'[data-modal-target]'</span>).forEach(btn =&gt; {\n btn.addEventListener(<span>'click'</span>, () =&gt; {\n <span>const</span> modal = document.getElementById(btn.dataset.modalTarget);\n <span>if</span> (modal) modal.classList.add(<span>'is-open'</span>);\n });\n});\ndocument.querySelectorAll(<span>'[data-modal-close]'</span>).forEach(btn =&gt; {\n btn.addEventListener(<span>'click'</span>, () =&gt; {\n btn.closest(<span>'.db-modal-backdrop'</span>).classList.remove(<span>'is-open'</span>);\n });\n});\n<span>// close modal on backdrop click (but not when clicking inside the modal box)</span>\ndocument.querySelectorAll(<span>'.db-modal-backdrop'</span>).forEach(backdrop =&gt; {\n backdrop.addEventListener(<span>'click'</span>, (e) =&gt; {\n <span>if</span> (e.target === backdrop) backdrop.classList.remove(<span>'is-open'</span>);\n });\n});\n\n<span>// ---- render the usage bar chart from a data attribute ----</span>\n<span>function</span> <span>renderBarChart</span>(svg) {\n <span>const</span> values = svg.dataset.values.split(<span>','</span>).map(<span>Number</span>);\n <span>const</span> w = <span>700</span>, h = <span>220</span>, pad = <span>28</span>;\n <span>const</span> max = Math.max(...values, <span>1</span>);\n <span>const</span> barW = (w - pad * <span>2</span>) / values.length - <span>10</span>;\n\n svg.innerHTML = <span>''</span>;\n values.forEach((v, i) =&gt; {\n <span>const</span> barH = (v / max) * (h - pad * <span>2</span>);\n <span>const</span> x = pad + i * ((w - pad * <span>2</span>) / values.length);\n <span>const</span> y = h - pad - barH;\n\n <span>const</span> rect = document.createElementNS(<span>'http://www.w3.org/2000/svg'</span>, <span>'rect'</span>);\n rect.setAttribute(<span>'x'</span>, x);\n rect.setAttribute(<span>'y'</span>, y);\n rect.setAttribute(<span>'width'</span>, barW);\n rect.setAttribute(<span>'height'</span>, barH);\n rect.setAttribute(<span>'rx'</span>, <span>3</span>);\n svg.appendChild(rect);\n });\n}\ndocument.querySelectorAll(<span>'.bar-chart[data-values]'</span>).forEach(renderBarChart);</pre>\n</div>\n<div>All selectors use <code>data-*</code> attributes (<code>data-modal-target</code>, <code>data-modal-close</code>) instead of inline <code>onclick</code> handlers. That keeps behavior in one JS file, lets Django templates stay free of script logic, and means Content-Security-Policy headers (Step 25) don't need an <code>unsafe-inline</code> exception.</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> if a chart needs tooltips, zoom, or real-time updates later, this hand-rolled SVG renderer is a clean seam to swap out for Chart.js without touching any other dashboard JS.</div>\n</section>\n<section class=\"step\" id=\"s17\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-success\">17</div>\n<h2>Product models and the dashboard layout template</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Every product model needs a tenant boundary (the <code>organization</code> FK) and a manager that enforces it, so a single missed <code>.filter()</code> in a view can't leak one company's data into another's screen.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">dashboard/models.py</span>\n</div>\n<pre><span>from</span> django.conf <span>import</span> settings\n<span>from</span> django.db <span>import</span> models\n\n\n<span>class</span> <span>Project</span>(models.Model):\n STATUS_CHOICES = [\n (<span>\"active\"</span>, <span>\"Active\"</span>), (<span>\"paused\"</span>, <span>\"Paused\"</span>), (<span>\"done\"</span>, <span>\"Done\"</span>),\n ]\n organization = models.ForeignKey(<span>\"accounts.Organization\"</span>, on_delete=models.CASCADE, related_name=<span>\"projects\"</span>)\n owner = models.ForeignKey(settings.AUTH_USER_MODEL, on_delete=models.SET_NULL, null=<span>True</span>)\n name = models.CharField(max_length=<span>160</span>)\n description = models.TextField(blank=<span>True</span>)\n status = models.CharField(max_length=<span>10</span>, choices=STATUS_CHOICES, default=<span>\"active\"</span>)\n created_at = models.DateTimeField(auto_now_add=<span>True</span>)\n updated_at = models.DateTimeField(auto_now=<span>True</span>)\n\n <span>class</span> <span>Meta</span>:\n ordering = [<span>\"-updated_at\"</span>]\n\n <span>@property</span>\n <span>def</span> <span>status_color</span>(self):\n <span>return</span> {<span>\"active\"</span>: <span>\"success\"</span>, <span>\"paused\"</span>: <span>\"warning\"</span>, <span>\"done\"</span>: <span>\"neutral\"</span>}[self.status]\n\n <span>def</span> <span>__str__</span>(self):\n <span>return</span> self.name</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">dashboard/views.py</span>\n</div>\n<pre><span>from</span> django.contrib.auth.decorators <span>import</span> login_required\n<span>from</span> django.shortcuts <span>import</span> redirect, render\n<span>from</span> django.utils.decorators <span>import</span> method_decorator\n<span>from</span> django.views <span>import</span> View\n\n<span>from</span> .models <span>import</span> Project\n\n\n<span>@login_required</span>\n<span>def</span> <span>home</span>(request):\n org = request.organization\n projects = Project.objects.filter(organization=org)\n stats = {\n <span>\"active_projects\"</span>: projects.filter(status=<span>\"active\"</span>).count(),\n <span>\"projects_delta\"</span>: <span>12</span>,\n <span>\"member_count\"</span>: org.memberships.count() <span>if</span> org <span>else</span> <span>0</span>,\n <span>\"mrr\"</span>: <span>0</span> <span>if</span> org.plan == <span>\"free\"</span> <span>else</span> <span>49</span>,\n <span>\"mrr_delta\"</span>: <span>8</span>,\n <span>\"open_tickets\"</span>: <span>3</span>,\n <span>\"tickets_delta\"</span>: <span>5</span>,\n <span>\"daily_usage\"</span>: <span>\"40,65,52,80,95,60,72\"</span>,\n }\n <span>return</span> render(request, <span>\"dashboard/home.html\"</span>, {<span>\"stats\"</span>: stats})\n\n\n<span>@login_required</span>\n<span>def</span> <span>projects</span>(request):\n qs = Project.objects.filter(organization=request.organization)\n <span>return</span> render(request, <span>\"dashboard/projects.html\"</span>, {<span>\"projects\"</span>: qs})\n\n\n<span>@login_required</span>\n<span>def</span> <span>project_create</span>(request):\n <span>if</span> request.method == <span>\"POST\"</span>:\n Project.objects.create(\n organization=request.organization,\n owner=request.user,\n name=request.POST[<span>\"name\"</span>],\n description=request.POST.get(<span>\"description\"</span>, <span>\"\"</span>),\n )\n <span>return</span> redirect(<span>\"dashboard:projects\"</span>)</pre>\n</div>\n<div class=\"step-body\">\n<p>Finally, the shared dashboard layout that every screen above (<code>home.html</code>, <code>projects.html</code>) extends:</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/dashboard/_layout.html</span>\n</div>\n<pre>{% <span>extends</span> \"base.html\" %}\n{% <span>load</span> static %}\n\n{% <span>block</span> extra_css %}\n &lt;<span>link</span> <span>rel</span>=<span>\"stylesheet\"</span> <span>href</span>=<span>\"{% static 'css/dashboard.css' %}\"</span>&gt;\n{% <span>endblock</span> %}\n\n{% <span>block</span> body %}\n&lt;<span>body</span> <span>class</span>=<span>\"db-body\"</span>&gt;\n&lt;<span>div</span> <span>class</span>=<span>\"db-shell\"</span>&gt;\n {% <span>include</span> \"dashboard/_sidebar.html\" %}\n &lt;<span>div</span> <span>class</span>=<span>\"db-main\"</span>&gt;\n {% <span>include</span> \"dashboard/_topbar.html\" %}\n &lt;<span>main</span> <span>class</span>=<span>\"db-content\"</span>&gt;\n {% <span>block</span> dashboard_content %}{% <span>endblock</span> %}\n &lt;/<span>main</span>&gt;\n &lt;/<span>div</span>&gt;\n&lt;/<span>div</span>&gt;\n{% <span>include</span> \"dashboard/_new_project_modal.html\" %}\n&lt;/<span>body</span>&gt;\n{% <span>endblock</span> %}\n\n{% <span>block</span> extra_js %}\n &lt;<span>script</span> <span>src</span>=<span>\"{% static 'js/dashboard.js' %}\"</span>&gt;&lt;/<span>script</span>&gt;\n{% <span>endblock</span> %}</pre>\n</div>\n<div class=\"tone-danger\"><strong>Watch out:</strong> <code>base.html</code> already opens a <code>&lt;body&gt;</code> tag inside its own <code>{% block body %}</code>. Overriding that block here and writing a second <code>&lt;body&gt;</code> tag would be invalid HTML in a real project -- restructure <code>base.html</code> so the outer shell only renders <code>&lt;html&gt;</code>/<code>&lt;head&gt;</code> and lets every page's body block supply its own <code>&lt;body&gt;</code>, exactly as shown above.</div>\n</section>\n<section class=\"step\" id=\"s18\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-success\">18</div>\n<h2>Billing with Stripe</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Stripe Checkout handles card collection, 3D Secure, and PCI compliance for you -- your app never touches raw card numbers. A webhook is the only reliable way to know a payment actually succeeded, since the user's browser can close before redirecting back.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/billing.py</span>\n</div>\n<pre><span>import</span> stripe\n<span>from</span> django.conf <span>import</span> settings\n\nstripe.api_key = settings.STRIPE_SECRET_KEY\n\n\n<span>def</span> <span>create_checkout_session</span>(organization, price_id, success_url, cancel_url):\n <span>if</span> <span>not</span> organization.stripe_customer_id:\n customer = stripe.Customer.create(name=organization.name)\n organization.stripe_customer_id = customer.id\n organization.save(update_fields=[<span>\"stripe_customer_id\"</span>])\n\n <span>return</span> stripe.checkout.Session.create(\n customer=organization.stripe_customer_id,\n mode=<span>\"subscription\"</span>,\n line_items=[{<span>\"price\"</span>: price_id, <span>\"quantity\"</span>: <span>1</span>}],\n success_url=success_url,\n cancel_url=cancel_url,\n client_reference_id=<span>str</span>(organization.id),\n )</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/views.py (billing views)</span>\n</div>\n<pre><span>import</span> stripe\n<span>from</span> django.conf <span>import</span> settings\n<span>from</span> django.http <span>import</span> HttpResponse\n<span>from</span> django.views.decorators.csrf <span>import</span> csrf_exempt\n\n<span>from</span> .models <span>import</span> Organization\n<span>from</span> .billing <span>import</span> create_checkout_session\n\n\n<span>@login_required</span>\n<span>def</span> <span>start_checkout</span>(request, price_id):\n session = create_checkout_session(\n organization=request.organization,\n price_id=price_id,\n success_url=request.build_absolute_uri(<span>\"/billing/success/\"</span>),\n cancel_url=request.build_absolute_uri(<span>\"/billing/\"</span>),\n )\n <span>return</span> redirect(session.url, permanent=<span>False</span>)\n\n\n<span>@csrf_exempt</span>\n<span>def</span> <span>stripe_webhook</span>(request):\n payload = request.body\n sig_header = request.META.get(<span>\"HTTP_STRIPE_SIGNATURE\"</span>)\n <span>try</span>:\n event = stripe.Webhook.construct_event(payload, sig_header, settings.STRIPE_WEBHOOK_SECRET)\n <span>except</span> (<span>ValueError</span>, stripe.error.SignatureVerificationError):\n <span>return</span> HttpResponse(status=<span>400</span>)\n\n <span>if</span> event[<span>\"type\"</span>] == <span>\"checkout.session.completed\"</span>:\n session = event[<span>\"data\"</span>][<span>\"object\"</span>]\n org_id = session.get(<span>\"client_reference_id\"</span>)\n Organization.objects.filter(id=org_id).update(plan=<span>\"pro\"</span>)\n\n <span>elif</span> event[<span>\"type\"</span>] == <span>\"customer.subscription.deleted\"</span>:\n customer_id = event[<span>\"data\"</span>][<span>\"object\"</span>][<span>\"customer\"</span>]\n Organization.objects.filter(stripe_customer_id=customer_id).update(plan=<span>\"free\"</span>)\n\n <span>return</span> HttpResponse(status=<span>200</span>)</pre>\n</div>\n<div>Register the webhook URL in your Stripe dashboard pointing at <code>https://yourdomain.com/billing/webhook/</code>, listening for <code>checkout.session.completed</code> and <code>customer.subscription.deleted</code> at minimum. In local dev, use the <code>stripe listen --forward-to localhost:8000/billing/webhook/</code> CLI command to test webhooks without deploying.</div>\n<div class=\"tone-danger\"><strong>Watch out:</strong> <code>stripe_webhook</code> is <code>@csrf_exempt</code> on purpose -- Stripe's servers can't supply a Django CSRF token. Signature verification via <code>STRIPE_WEBHOOK_SECRET</code> is what actually protects this endpoint, so never remove that check.</div>\n</section>\n<section class=\"step\" id=\"s19\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-success\">19</div>\n<h2>Permissions and plan limits</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>\"Free plan allows 3 projects, Pro allows unlimited\" is the kind of rule that's easy to bolt on inconsistently across views. Centralizing it in one place means upgrading the rule later -- or the plan itself -- is a one-line change.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/permissions.py</span>\n</div>\n<pre><span>from</span> django.core.exceptions <span>import</span> PermissionDenied\n\nPLAN_LIMITS = {\n <span>\"free\"</span>: {<span>\"max_projects\"</span>: <span>3</span>, <span>\"max_members\"</span>: <span>2</span>},\n <span>\"pro\"</span>: {<span>\"max_projects\"</span>: <span>50</span>, <span>\"max_members\"</span>: <span>10</span>},\n <span>\"team\"</span>: {<span>\"max_projects\"</span>: <span>None</span>, <span>\"max_members\"</span>: <span>None</span>}, <span># None = unlimited</span>\n}\n\n\n<span>def</span> <span>enforce_project_limit</span>(organization):\n limit = PLAN_LIMITS[organization.plan][<span>\"max_projects\"</span>]\n <span>if</span> limit <span>is</span> <span>not</span> <span>None</span> <span>and</span> organization.projects.count() &gt;= limit:\n <span>raise</span> PermissionDenied(\n <span>f</span><span>\"Your {organization.get_plan_display()} plan allows up to {limit} projects. Upgrade to add more.\"</span>\n )\n\n\n<span>def</span> <span>require_role</span>(user, organization, allowed_roles):\n membership = organization.memberships.filter(user=user).first()\n <span>if</span> <span>not</span> membership <span>or</span> membership.role <span>not</span> <span>in</span> allowed_roles:\n <span>raise</span> PermissionDenied(<span>\"You don't have permission to do that.\"</span>)</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">dashboard/views.py (updated project_create)</span>\n</div>\n<pre><span>from</span> accounts.permissions <span>import</span> enforce_project_limit\n\n\n<span>@login_required</span>\n<span>def</span> <span>project_create</span>(request):\n <span>if</span> request.method == <span>\"POST\"</span>:\n enforce_project_limit(request.organization) <span># raises PermissionDenied -&gt; Django renders 403.html</span>\n Project.objects.create(\n organization=request.organization, owner=request.user,\n name=request.POST[<span>\"name\"</span>], description=request.POST.get(<span>\"description\"</span>, <span>\"\"</span>),\n )\n <span>return</span> redirect(<span>\"dashboard:projects\"</span>)</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> create a custom <code>templates/403.html</code> that shows the <code>PermissionDenied</code> message with an \"Upgrade plan\" button linking to <code>dashboard:billing</code> -- it turns a hard limit into a conversion opportunity instead of a dead end.</div>\n</section>\n<section class=\"step\" id=\"s20\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-success\">20</div>\n<h2>Background tasks (email, reports)</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Sending a welcome email or generating a usage report inside the request/response cycle makes the user wait for work that doesn't need to block their page load. Offloading it to a worker keeps the dashboard feeling instant.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install celery redis\npip freeze &gt; requirements.txt</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/celery.py</span>\n</div>\n<pre><span>import</span> os\n<span>from</span> celery <span>import</span> Celery\n\nos.environ.setdefault(<span>\"DJANGO_SETTINGS_MODULE\"</span>, <span>\"core.settings.dev\"</span>)\n\napp = Celery(<span>\"core\"</span>)\napp.config_from_object(<span>\"django.conf:settings\"</span>, namespace=<span>\"CELERY\"</span>)\napp.autodiscover_tasks()</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/tasks.py</span>\n</div>\n<pre><span>from</span> celery <span>import</span> shared_task\n<span>from</span> django.core.mail <span>import</span> send_mail\n\n\n<span>@shared_task</span>\n<span>def</span> <span>send_welcome_email</span>(user_email):\n send_mail(\n subject=<span>\"Welcome to SaaSDash\"</span>,\n message=<span>\"Thanks for signing up -- let's get your first project set up.\"</span>,\n from_email=<span>\"hello@yourdomain.com\"</span>,\n recipient_list=[user_email],\n )</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/views.py (call site, inside SignupView.post)</span>\n</div>\n<pre>login(request, user)\nsend_welcome_email.delay(user.email) <span># queued, doesn't block the redirect</span>\n<span>return</span> redirect(<span>\"dashboard:home\"</span>)</pre>\n</div>\n<div>Celery needs a message broker -- Redis is the simplest choice. Run a worker alongside your web server: <code>celery -A core worker --loglevel=info</code>. Most hosting platforms run this as a second process type next to the web dyno/service.</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> if your traffic is low and you want to avoid running Redis at all, <code>django-q2</code> with the ORM as its broker is a lighter-weight alternative for early-stage SaaS apps.</div>\n</section>\n<section class=\"step\" id=\"s21\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">21</div>\n<h2>Environment variables</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Every secret your app needs -- database URL, Stripe keys, the Django secret key -- has to come from the environment in production, never from a checked-in file. Setting this up properly now means deploying to any host is just \"set these variables.\"</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">.env (local only -- never commit)</span>\n</div>\n<pre>SECRET_KEY=replace-with-a-real-random-key\nDEBUG=True\nDJANGO_SETTINGS_MODULE=core.settings.dev\n\nSTRIPE_SECRET_KEY=sk_test_...\nSTRIPE_PUBLISHABLE_KEY=pk_test_...\nSTRIPE_WEBHOOK_SECRET=whsec_...</pre>\n</div>\n<div class=\"table-wrap\">\n<table>\n<tr><th>Variable</th><th>Set where</th></tr>\n<tr><td><code>SECRET_KEY</code></td><td>Local <code>.env</code> / host's env panel -- always unique per environment</td></tr>\n<tr><td><code>DATABASE_URL</code></td><td>Provided automatically by most hosts when you add a Postgres add-on</td></tr>\n<tr><td><code>ALLOWED_HOSTS</code></td><td>Your production domain(s), comma-separated</td></tr>\n<tr><td><code>STRIPE_SECRET_KEY</code></td><td>Test key locally, live key in production -- never mix them</td></tr>\n<tr><td><code>DJANGO_SETTINGS_MODULE</code></td><td><code>core.settings.dev</code> locally, <code>core.settings.prod</code> on the server</td></tr>\n</table>\n</div>\n<div class=\"tone-danger\"><strong>Watch out:</strong> Stripe test keys (<code>sk_test_...</code>) and live keys (<code>sk_live_...</code>) point at completely separate data. A subscription created with a test key will never show up in your live dashboard, and vice versa -- a common source of \"where did my test payment go\" confusion.</div>\n</section>\n<section class=\"step\" id=\"s22\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">22</div>\n<h2>Switch to PostgreSQL</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>SQLite is a single file and can't handle concurrent writes well -- fine for development, risky in production where multiple Gunicorn workers write at once. Postgres is the standard, battle-tested choice for Django in production.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre><span># local Postgres setup, if you want production parity in dev too</span>\ncreatedb saasdash\npip install dj-database-url\npip freeze &gt; requirements.txt</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">.env (when testing prod settings locally)</span>\n</div>\n<pre>DATABASE_URL=postgres://user:password@localhost:5432/saasdash</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>python manage.py migrate\npython manage.py createsuperuser</pre>\n</div>\n<div>Most hosting platforms (Railway, Render, Heroku, Fly.io) provision a managed Postgres instance and inject <code>DATABASE_URL</code> into your app's environment automatically -- you usually don't need to set it by hand in production.</div>\n</section>\n<section class=\"step\" id=\"s23\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">23</div>\n<h2>Static and media files</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django's development server serves CSS/JS automatically, but it refuses to in production by design. <code>collectstatic</code> plus Whitenoise is the simplest way to serve them correctly without standing up a separate CDN.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>python manage.py collectstatic --noinput</pre>\n</div>\n<div>This copies every file from <code>STATICFILES_DIRS</code> (your <code>static/</code> source folder) and each app's own <code>static/</code> folder into <code>STATIC_ROOT</code> (<code>staticfiles/</code>), with content-hashed filenames for cache-busting -- that's what <code>CompressedManifestStaticFilesStorage</code> from Step 6 does. Run this command every time you deploy, after pulling new code, before starting Gunicorn.</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> user-uploaded files (avatars, attachments) belong in <code>MEDIA_ROOT</code>, not <code>STATIC_ROOT</code> -- they're not part of your codebase. In production, point <code>MEDIA_ROOT</code> at persistent storage (an S3 bucket via <code>django-storages</code>) rather than the server's local disk, which can be wiped on every redeploy on some hosts.</div>\n</section>\n<section class=\"step\" id=\"s24\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">24</div>\n<h2>Gunicorn + Nginx</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django's own dev server is single-threaded and not hardened for the open internet. Gunicorn runs multiple worker processes to handle real traffic; Nginx sits in front to terminate TLS and serve files efficiently.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>gunicorn core.wsgi:application --bind 0.0.0.0:8000 --workers 3</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">Procfile (for Railway / Heroku-style platforms)</span>\n</div>\n<pre>release: python manage.py migrate\nweb: gunicorn core.wsgi:application --bind 0.0.0.0:$PORT --workers 3\nworker: celery -A core worker --loglevel=info</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">/etc/nginx/sites-available/saasdash (self-managed VPS only)</span>\n</div>\n<pre>server {\n listen 80;\n server_name yourdomain.com;\n\n location /static/ {\n alias /path/to/saasdash/staticfiles/;\n }\n location /media/ {\n alias /path/to/saasdash/media/;\n }\n location / {\n proxy_pass http://127.0.0.1:8000;\n proxy_set_header Host $host;\n proxy_set_header X-Real-IP $remote_addr;\n proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n proxy_set_header X-Forwarded-Proto $scheme;\n }\n}</pre>\n</div>\n<div>If you're deploying to a platform-as-a-service (Railway, Render, Fly.io) rather than a bare VPS, you usually don't need to configure Nginx yourself -- the platform's router handles TLS and proxying, and Whitenoise (already in <code>MIDDLEWARE</code> from Step 6) serves your static files directly from Gunicorn.</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> always run an Nginx or platform proxy in front of Gunicorn for a public-facing app -- it adds TLS termination, request buffering, and protection against slow-client attacks that Gunicorn alone doesn't handle well.</div>\n</section>\n<section class=\"step\" id=\"s25\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">25</div>\n<h2>Pre-deploy checklist</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django's built-in deployment check catches the most common security misconfigurations automatically -- running it, plus a manual pass down this list, is the last gate before going live.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>DJANGO_SETTINGS_MODULE=core.settings.prod python manage.py check --deploy\npython manage.py migrate\npython manage.py collectstatic --noinput</pre>\n</div>\n<div class=\"checklist\">\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>DEBUG = False</strong> in <code>core/settings/prod.py</code> -- a stack trace leaking to the public is a real vulnerability, not just a cosmetic issue.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>SECRET_KEY</strong> is long, random, and lives only in environment variables -- never in source control.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>ALLOWED_HOSTS</strong> lists only your real domain(s), not <code>\"*\"</code>.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>HTTPS enforced</strong> via <code>SECURE_SSL_REDIRECT = True</code> and HSTS headers configured.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>DATABASE_URL</strong> points at PostgreSQL, not the SQLite file.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>STATIC_ROOT</strong> is populated -- <code>collectstatic</code> has been run on this exact deploy.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>Stripe is in live mode</strong> with the live webhook secret, and the webhook endpoint is registered in the Stripe dashboard.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>Celery worker is running</strong> (if used) as a separate process, not just the web process.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>Error tracking configured</strong> (Sentry or similar) so production exceptions don't vanish silently.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>Database backups enabled</strong> -- most managed Postgres add-ons offer automatic daily backups; turn this on before you have real customer data.</span></div>\n</div>\n</section>\n<section id=\"cheatsheet\">\n<h2>SaaS Dashboard Cheat Sheet</h2>\n<p class=\"section-sub\">Quick-reference commands, multi-tenancy patterns, and the dashboard CSS primitives.</p>\n<div class=\"cheat-grid\">\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span>\u2328</span><h3>Management Commands</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>startproject core .</code><span>Scaffold project in current directory</span></div>\n<div class=\"cheat-item\"><code>startapp name</code><span>Create a new app</span></div>\n<div class=\"cheat-item\"><code>makemigrations</code><span>Generate migration files from model changes</span></div>\n<div class=\"cheat-item\"><code>migrate</code><span>Apply pending migrations to the database</span></div>\n<div class=\"cheat-item\"><code>createsuperuser</code><span>Create an admin account interactively</span></div>\n<div class=\"cheat-item\"><code>collectstatic</code><span>Gather all static files into STATIC_ROOT</span></div>\n<div class=\"cheat-item\"><code>check --deploy</code><span>Run security checks for production</span></div>\n<div class=\"cheat-item\"><code>shell</code><span>Open an interactive Python shell with Django loaded</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Multi-Tenancy Patterns</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>request.organization</code><span>Current tenant, resolved by middleware on every request</span></div>\n<div class=\"cheat-item\"><code>Model.objects.filter(organization=...)</code><span>Always scope product querysets to the tenant</span></div>\n<div class=\"cheat-item\"><code>Membership</code><span>Join table linking users \u2194 organizations with a role</span></div>\n<div class=\"cheat-item\"><code>unique_together</code><span>Prevents the same user joining one org twice</span></div>\n<div class=\"cheat-item\"><code>session[\"active_org_id\"]</code><span>Tracks which org a multi-org user is currently viewing</span></div>\n<div class=\"cheat-item\"><code>transaction.atomic()</code><span>Wrap signup so user + org creation succeed or fail together</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Template Tags and Filters</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>{% url 'app:name' arg %}</code><span>Reverse URL lookup by name</span></div>\n<div class=\"cheat-item\"><code>{% load static %}</code><span>Enable static tag in template</span></div>\n<div class=\"cheat-item\"><code>{% static 'path' %}</code><span>Output URL for a static file</span></div>\n<div class=\"cheat-item\"><code>{% csrf_token %}</code><span>Required inside every POST form</span></div>\n<div class=\"cheat-item\"><code>{% include \"x.html\" %}</code><span>Insert a reusable partial (sidebar, topbar, modal)</span></div>\n<div class=\"cheat-item\"><code>{% block name %}{% endblock %}</code><span>Define overrideable region</span></div>\n<div class=\"cheat-item\"><code>{{ val|timesince }}</code><span>Render \"3 hours ago\" style relative time</span></div>\n<div class=\"cheat-item\"><code>{{ val|default:\"None\" }}</code><span>Fallback if value is falsy</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Security Settings</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>SECURE_SSL_REDIRECT</code><span>Force all HTTP to HTTPS (set True in prod)</span></div>\n<div class=\"cheat-item\"><code>SESSION_COOKIE_SECURE</code><span>Only send session cookie over HTTPS</span></div>\n<div class=\"cheat-item\"><code>CSRF_COOKIE_SECURE</code><span>Only send CSRF cookie over HTTPS</span></div>\n<div class=\"cheat-item\"><code>SECURE_HSTS_SECONDS</code><span>Set HSTS header (e.g. 31536000 for 1 year)</span></div>\n<div class=\"cheat-item\"><code>X_FRAME_OPTIONS</code><span>Set to \"DENY\" to block clickjacking</span></div>\n<div class=\"cheat-item\"><code>@csrf_exempt</code><span>Use sparingly -- only for verified webhook endpoints</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Stripe Billing</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>stripe.Customer.create()</code><span>Create a billing customer for an organization</span></div>\n<div class=\"cheat-item\"><code>stripe.checkout.Session.create()</code><span>Start a hosted Checkout flow</span></div>\n<div class=\"cheat-item\"><code>checkout.session.completed</code><span>Webhook event fired after successful payment</span></div>\n<div class=\"cheat-item\"><code>customer.subscription.deleted</code><span>Webhook event fired on cancellation</span></div>\n<div class=\"cheat-item\"><code>stripe listen --forward-to</code><span>CLI command to test webhooks locally</span></div>\n<div class=\"cheat-item\"><code>client_reference_id</code><span>Pass your org ID through Checkout to identify it in webhooks</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Dashboard CSS Primitives</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>.card</code><span>Base bordered surface used by every panel</span></div>\n<div class=\"cheat-item\"><code>.btn-primary / .btn-secondary</code><span>Filled vs outline action buttons</span></div>\n<div class=\"cheat-item\"><code>.badge-success/-warning/-danger</code><span>Status pills with semantic color</span></div>\n<div class=\"cheat-item\"><code>.db-table</code><span>Bordered, hoverable data table</span></div>\n<div class=\"cheat-item\"><code>.db-modal-backdrop.is-open</code><span>JS toggles this class to show/hide modals</span></div>\n<div class=\"cheat-item\"><code>--db-*</code> custom properties<span>Central token set for the whole dashboard theme</span></div>\n</div>\n</div>\n</div>\n</section>";

